class Solution {
    public boolean isPossible(int[] nums) {
        Map<Integer, Integer> countMap = new HashMap<>();
        Map<Integer, Integer> groupMap = new HashMap<>();

        for (int num : nums) {
            countMap.put(num, countMap.getOrDefault(num, 0) + 1);
        }

        for (int num : nums) {
            if (countMap.get(num) > 0) {
                if ((groupMap.getOrDefault(num - 1, 0) > 0)) {
                    groupMap.put(num - 1, groupMap.get(num - 1) - 1);
                    groupMap.put(num, groupMap.getOrDefault(num, 0) + 1);
                    countMap.put(num, countMap.get(num) - 1);
                } else if (countMap.getOrDefault(num + 1, 0) > 0 && countMap.getOrDefault(num + 2, 0) > 0) {
                    countMap.put(num, countMap.get(num) - 1);
                    countMap.put(num + 1, countMap.get(num + 1) - 1);
                    countMap.put(num + 2, countMap.get(num + 2) - 1);
                    groupMap.put(num + 2, groupMap.getOrDefault(num + 2, 0) + 1);
                } else {
                    return false;
                }
            }
        }
        return true;
    }
}
